function solve(grid, k) {
    const m = grid.length;
    if (m === 0) return 0;
    const n = grid[0].length;
    const visited = new Array(m).fill().map(() => new Array(n).fill(false));
    let count = 0;

    const dfs = (i, j) => {
        if (i < 0 || i >= m || j < 0 || j >= n || grid[i][j] === 0 || visited[i][j]) {
            return 0;
        }
        visited[i][j] = true;
        let sum = grid[i][j];
        sum += dfs(i + 1, j);
        sum += dfs(i - 1, j);
        sum += dfs(i, j + 1);
        sum += dfs(i, j - 1);
        return sum;
    };

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] > 0 && !visited[i][j]) {
                const sum = dfs(i, j);
                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }
    return count;
}

